function draw() {
    ctx.save();

    // Screen shake
    if (shakeTimer > 0) {
        let sx = (Math.random() - 0.5) * shakeIntensity * (shakeTimer / 15);
        let sy = (Math.random() - 0.5) * shakeIntensity * (shakeTimer / 15);
        ctx.translate(sx, sy);
    }

    // Clear
    ctx.fillStyle = '#0a0a2e';
    ctx.fillRect(-10, -10, canvas.width + 20, canvas.height + 20);

    if (gameState === 'start') {
        drawStartScreen();
        ctx.restore();
        return;
    }

    // Draw star field
    drawStarField();

    // Draw game elements
    drawBricks();
    drawPowerups();
    drawPaddle();

    // Draw main ball
    if (ball.launched || gameState === 'playing') {
        drawBall(ball, ball.color);
    } else {
        drawBall(ball, '#aaaaff');
    }

    // Draw extra balls
    for (let eb of extraBalls) {
        drawBall(eb, eb.color);
    }

    drawParticles();
    drawNotifications();
    drawHUD();

    // Launch hint
    if (!ball.launched && gameState === 'playing') {
        let alpha = Math.sin(Date.now() * 0.005) * 0.3 + 0.7;
        ctx.globalAlpha = alpha;
        ctx.fillStyle = '#ffffff';
        ctx.font = '16px Arial';
        ctx.textAlign = 'center';
        ctx.fillText('点击或按空格发射球', canvas.width / 2, canvas.height / 2 + 50);
        ctx.globalAlpha = 1;
    }

    ctx.restore();

    // Overlay screens (not affected by shake)
    if (gameState === 'gameover') drawGameOverScreen();
    if (gameState === 'win') drawWinScreen();
    if (gameState === 'paused') drawPausedScreen();
}

// CanvasRenderingContext2D roundRect polyfill
if (!CanvasRenderingContext2D.prototype.roundRect) {
    CanvasRenderingContext2D.prototype.roundRect = function(x, y, w, h, r) {
        if (typeof r === 'number') r = [r, r, r, r];
        this.moveTo(x + r[0], y);
        this.lineTo(x + w - r[1], y);
        this.quadraticCurveTo(x + w, y, x + w, y + r[1]);
        this.lineTo(x + w, y + h - r[2]);
        this.quadraticCurveTo(x + w, y + h, x + w - r[2], y + h);
        this.lineTo(x + r[3], y + h);
        this.quadraticCurveTo(x, y + h, x, y + h - r[3]);
        this.lineTo(x, y + r[0]);
        this.quadraticCurveTo(x, y, x + r[0], y);
        this.closePath();
    };
}

function gameLoop() {
    update();
    draw();
    requestAnimationFrame(gameLoop);
}

gameLoop();
</script>
